#include <stdio.h>
#include <stdlib.h>

// Node structure
typedef struct Node {
    int data;
    struct Node* next;
} Node;

// Function to create a new node
Node* createNode(int data) {
    Node* newNode = (Node*) malloc(sizeof(Node));
    if (!newNode) {
        printf("Memory error\n");
        return NULL;
    }
    newNode->data = data;
    newNode->next = NULL;
    return newNode;
}

// Function to insert a node at the end of the list
void insertNode(Node** head, int data) {
    Node* newNode = createNode(data);
    if (*head == NULL) {
        *head = newNode;
        return;
    }

    Node* lastNode = *head;
    while (lastNode->next) {
        lastNode = lastNode->next;
    }

    lastNode->next = newNode;
}

// Function to print the linked list
void printList(Node* head) {
    while (head) {
        printf("%d ", head->data);
        head = head->next;
    }
    printf("\n");
}

// Function to reverse the linked list
Node* reverseList(Node* head) {
    Node* prev = NULL;
    Node* current = head;
    Node* next = NULL;

    while (current) {
        next = current->next;
        current->next = prev;
        prev = current;
        current = next;
    }

    return prev;
}

// Function to add one to the number represented by the linked list
Node* addOne(Node* head) {
    head = reverseList(head);
    Node* current = head;
    int carry = 1;

    while (current && carry) {
        int sum = current->data + carry;
        current->data = sum % 10;
        carry = sum / 10;

        if (!current->next && carry) {
            current->next = createNode(carry);
            carry = 0;
        }

        current = current->next;
    }

    head = reverseList(head);
    return head;
}

int main() {
    Node* head = NULL;
    insertNode(&head, 1);
    insertNode(&head, 2);
    insertNode(&head, 3);

    printf("Original Number: ");
    printList(head);

    head = addOne(head);

    printf("After Adding One: ");
    printList(head);

    return 0;
}

